Here are the public test cases for feature10_builder_validation:
{
  "description": "Reject invalid build requests. Compacting an empty builder is an illegal state; specifying both a plaintext payload and claims is an illegal state; supplying a non-HMAC algorithm with raw key bytes is an invalid argument.",
  "cases": [
    {
      "input": {
        "op": "builder_validate",
        "mode": "empty"
      },
      "expected_output": "error=illegal_state"
    },
    {
      "input": {
        "op": "builder_validate",
        "mode": "both_payload_and_claims"
      },
      "expected_output": "error=illegal_state"
    },
    {
      "input": {
        "op": "builder_validate",
        "mode": "bytes_without_hmac"
      },
      "expected_output": "error=illegal_argument"
    }
  ]
}

Here are the public test cases for feature11_forgery_resistance:
{
  "description": "Resist an algorithm-substitution forgery: an attacker re-signs a token with HMAC using an asymmetric public key's encoded bytes as the MAC secret. When the token is verified with the asymmetric key, the library refuses rather than accepting the forgery, surfacing a neutral error category.",
  "cases": [
    {
      "input": {
        "op": "forge_hmac_with_key",
        "key_type": "rsa"
      },
      "expected_output": "error=unsupported\nreason=algorithm_key_mismatch"
    },
    {
      "input": {
        "op": "forge_hmac_with_key",
        "key_type": "ec"
      },
      "expected_output": "error=unsupported\nreason=algorithm_key_mismatch"
    }
  ]
}

Here are the public test cases for feature1_signature_algorithm_metadata:
{
  "description": "Resolve signature-algorithm metadata by name: each algorithm exposes its canonical wire value, a human-readable description, an algorithm family, whether it is guaranteed by a standard platform runtime, and family predicates (HMAC / RSA / elliptic-curve). Names can also be looked up case-insensitively, and an unrecognized name is rejected.",
  "cases": [
    {
      "input": {
        "op": "algorithm_info",
        "name": "HS256"
      },
      "expected_output": "value=HS256\ndescription=HMAC using SHA-256\nfamily=HMAC\njdk_standard=true\nhmac=true\nrsa=false\nelliptic_curve=false"
    },
    {
      "input": {
        "op": "algorithm_info",
        "name": "RS256"
      },
      "expected_output": "value=RS256\ndescription=RSASSA-PKCS-v1_5 using SHA-256\nfamily=RSA\njdk_standard=true\nhmac=false\nrsa=true\nelliptic_curve=false"
    },
    {
      "input": {
        "op": "algorithm_info",
        "name": "ES256"
      },
      "expected_output": "value=ES256\ndescription=ECDSA using P-256 and SHA-256\nfamily=Elliptic Curve\njdk_standard=false\nhmac=false\nrsa=false\nelliptic_curve=true"
    },
    {
      "input": {
        "op": "algorithm_info",
        "name": "NONE"
      },
      "expected_output": "value=none\ndescription=No digital signature or MAC performed\nfamily=None\njdk_standard=false\nhmac=false\nrsa=false\nelliptic_curve=false"
    },
    {
      "input": {
        "op": "algorithm_for_name",
        "name": "hs256"
      },
      "expected_output": "value=HS256\nfamily=HMAC"
    },
    {
      "input": {
        "op": "algorithm_for_name",
        "name": "foo"
      },
      "expected_output": "error=signature_invalid"
    }
  ]
}

Here are the public test cases for feature2_unsecured_token_serialization:
{
  "description": "Serialize an unsecured token (no signature) into compact form. The header declares the 'none' algorithm, the payload is base64url-encoded, and an empty signature segment terminates the string. The wire output matches the canonical specification example byte-for-byte.",
  "cases": [
    {
      "input": {
        "op": "build_plaintext",
        "payload": "{\"iss\":\"joe\",\r\n \"exp\":1300819380,\r\n \"http://example.com/is_root\":true}"
      },
      "expected_output": "token=eyJhbGciOiJub25lIn0.eyJpc3MiOiJqb2UiLA0KICJleHAiOjEzMDA4MTkzODAsDQogImh0dHA6Ly9leGFtcGxlLmNvbS9pc19yb290Ijp0cnVlfQ."
    },
    {
      "input": {
        "op": "build_plaintext",
        "payload": "Hello world!"
      },
      "expected_output": "token=eyJhbGciOiJub25lIn0.SGVsbG8gd29ybGQh."
    }
  ]
}

Here are the public test cases for feature3_claims_roundtrip:
{
  "description": "Build a claims token using registered-claim convenience setters and arbitrary custom claims, then parse it back and recover the claim set. Setting a registered claim to null removes it. Date-valued claims (expiration / not-before / issued-at) are stored as integer seconds since the epoch.",
  "cases": [
    {
      "input": {
        "op": "build_parse_claims",
        "claims": {
          "iss": "Me"
        }
      },
      "expected_output": "iss=Me"
    },
    {
      "input": {
        "op": "build_parse_claims",
        "claims": {
          "iss": "Me",
          "sub": "Joe"
        },
        "unset": [
          "iss"
        ]
      },
      "expected_output": "sub=Joe"
    },
    {
      "input": {
        "op": "build_parse_claims",
        "claims": {
          "iss": "Iss",
          "sub": "Sub",
          "aud": "Aud",
          "jti": "Id"
        }
      },
      "expected_output": "iss=Iss\nsub=Sub\naud=Aud\njti=Id"
    },
    {
      "input": {
        "op": "build_parse_claims",
        "claims": {
          "exp": 9999999999000,
          "nbf": 1000000000000,
          "iat": 1000000000000
        }
      },
      "expected_output": "exp=9999999999\nnbf=1000000000\niat=1000000000"
    },
    {
      "input": {
        "op": "build_parse_claims",
        "claims": {
          "sub": "Joe",
          "role": "admin",
          "count": 5
        }
      },
      "expected_output": "sub=Joe\nclaim.count=5\nclaim.role=admin"
    }
  ]
}

Here are the public test cases for feature4_mac_signing:
{
  "description": "Sign a token with an HMAC-SHA algorithm using a fixed shared secret, producing a deterministic compact output, then verify it and recover the header algorithm and body. Works for claims bodies and arbitrary plaintext bodies across the HMAC family (256/384/512).",
  "cases": [
    {
      "input": {
        "op": "sign_verify",
        "alg": "HS256",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "claims": {
          "sub": "Joe"
        },
        "emit_token": true
      },
      "expected_output": "token=eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiJKb2UifQ.qs8rO_cGp7ctWsq-yGbVzJ-cjAhzdLh1jP0296AC9Ac\nalg=HS256\nsub=Joe"
    },
    {
      "input": {
        "op": "sign_verify",
        "alg": "HS384",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyAhIiMkJSYnKCkqKywtLi8w",
        "claims": {
          "sub": "Joe"
        }
      },
      "expected_output": "alg=HS384\nsub=Joe"
    },
    {
      "input": {
        "op": "sign_verify",
        "alg": "HS512",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyAhIiMkJSYnKCkqKywtLi8wMTIzNDU2Nzg5Ojs8PT4_QA",
        "payload": "Hello world!"
      },
      "expected_output": "alg=HS512\nbody=Hello world!"
    }
  ]
}

Here are the public test cases for feature5_payload_compression:
{
  "description": "Compress the token body before signing and transparently decompress it on parse. The header records the compression algorithm. Supports the two built-in codecs (DEFLATE, GZIP) and a caller-supplied custom codec resolved by name during parsing.",
  "cases": [
    {
      "input": {
        "op": "compress_roundtrip",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "codec": "DEF",
        "claims": {
          "sub": "Joe"
        }
      },
      "expected_output": "calg=DEF\nsub=Joe"
    },
    {
      "input": {
        "op": "compress_roundtrip",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "codec": "GZIP",
        "claims": {
          "sub": "Joe"
        }
      },
      "expected_output": "calg=GZIP\nsub=Joe"
    },
    {
      "input": {
        "op": "compress_roundtrip",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "codec": "CUSTOM",
        "claims": {
          "sub": "Joe"
        }
      },
      "expected_output": "calg=CUSTOM\nsub=Joe"
    }
  ]
}

Here are the public test cases for feature6_token_parsing:
{
  "description": "Parse an arbitrary compact token without asserting its shape: recover the header algorithm and the body (claims or plaintext). Structurally invalid strings are rejected with a neutral error category and a reason (wrong number of separators, missing body), and a null input is rejected as an invalid argument.",
  "cases": [
    {
      "input": {
        "op": "parse",
        "token": "foo"
      },
      "expected_output": "error=malformed\nreason=period_count"
    },
    {
      "input": {
        "op": "parse",
        "token": "."
      },
      "expected_output": "error=malformed\nreason=period_count"
    },
    {
      "input": {
        "op": "parse",
        "token": ".."
      },
      "expected_output": "error=malformed\nreason=missing_body"
    },
    {
      "input": {
        "op": "parse",
        "token": "eyJhbGciOiJub25lIn0.SGVsbG8gd29ybGQh."
      },
      "expected_output": "alg=none\nbody=Hello world!"
    },
    {
      "input": {
        "op": "parse",
        "token": "eyJhbGciOiJub25lIn0.eyJzdWIiOiJKb2UifQ."
      },
      "expected_output": "alg=none\nsub=Joe"
    },
    {
      "input": {
        "op": "parse",
        "token": "eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiJKb2UifQ.qs8rO_cGp7ctWsq-yGbVzJ-cjAhzdLh1jP0296AC9Ac",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA"
      },
      "expected_output": "alg=HS256\nsub=Joe"
    },
    {
      "input": {
        "op": "parse",
        "token": null
      },
      "expected_output": "error=illegal_argument"
    }
  ]
}

Here are the public test cases for feature7_typed_parsing:
{
  "description": "Parse a token while asserting its exact shape (unsecured-plaintext, unsecured-claims, signed-plaintext, signed-claims). A token whose actual shape does not match the requested shape is rejected with a neutral 'unsupported' category and a reason; a signed token verified with the wrong key is rejected as an invalid signature.",
  "cases": [
    {
      "input": {
        "op": "parse_typed",
        "token": "eyJhbGciOiJub25lIn0.SGVsbG8gd29ybGQh.",
        "method": "plaintext_jwt"
      },
      "expected_output": "kind=plaintext_jwt\nbody=Hello world!"
    },
    {
      "input": {
        "op": "parse_typed",
        "token": "eyJhbGciOiJub25lIn0.eyJzdWIiOiJKb2UifQ.",
        "method": "claims_jwt"
      },
      "expected_output": "kind=claims_jwt\nsub=Joe"
    },
    {
      "input": {
        "op": "parse_typed",
        "token": "eyJhbGciOiJIUzI1NiJ9.SGVsbG8gd29ybGQh.4Luu4D1QDg0vorxFuBy4sFq090uoZMwkkGfVFsOeqTw",
        "method": "plaintext_jws",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA"
      },
      "expected_output": "kind=plaintext_jws\nalg=HS256\nbody=Hello world!"
    },
    {
      "input": {
        "op": "parse_typed",
        "token": "eyJhbGciOiJub25lIn0.SGVsbG8gd29ybGQh.",
        "method": "claims_jwt"
      },
      "expected_output": "error=unsupported\nreason=unsigned_plaintext_jwt"
    },
    {
      "input": {
        "op": "parse_typed",
        "token": "eyJhbGciOiJub25lIn0.eyJzdWIiOiJKb2UifQ.",
        "method": "plaintext_jwt"
      },
      "expected_output": "error=unsupported\nreason=unsigned_claims_jwt"
    },
    {
      "input": {
        "op": "parse_typed",
        "token": "eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiJKb2UifQ.qs8rO_cGp7ctWsq-yGbVzJ-cjAhzdLh1jP0296AC9Ac",
        "method": "claims_jws",
        "key": "Zm9vYmFyYmF6cXV4MTIzNDU2Nzg5MGFiY2RlZmdoaWprbA"
      },
      "expected_output": "error=signature_invalid"
    }
  ]
}

Here are the public test cases for feature8_required_claims:
{
  "description": "Assert that a parsed token contains required claims with expected values. A matching claim verifies successfully and recovers the claim set; a present-but-wrong value is rejected as an incorrect claim; a required-but-absent claim is rejected as a missing claim. Works for registered claims and custom claims.",
  "cases": [
    {
      "input": {
        "op": "require_claim",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "claims": {
          "sub": "Joe"
        },
        "require": {
          "name": "sub",
          "value": "Joe"
        }
      },
      "expected_output": "verified=true\nsub=Joe"
    },
    {
      "input": {
        "op": "require_claim",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "claims": {
          "sub": "Joe"
        },
        "require": {
          "name": "sub",
          "value": "Wrong"
        }
      },
      "expected_output": "error=incorrect_claim\nclaim=sub"
    },
    {
      "input": {
        "op": "require_claim",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "claims": {
          "sub": "Joe"
        },
        "require": {
          "name": "iss",
          "value": "Me"
        }
      },
      "expected_output": "error=missing_claim\nclaim=iss"
    },
    {
      "input": {
        "op": "require_claim",
        "key": "AQIDBAUGBwgJCgsMDQ4PEBESExQVFhcYGRobHB0eHyA",
        "claims": {
          "role": "admin"
        },
        "require": {
          "name": "role",
          "value": "admin"
        }
      },
      "expected_output": "verified=true\nclaim.role=admin"
    }
  ]
}

Here are the public test cases for feature9_temporal_validation:
{
  "description": "Enforce time-based validity on parse. A token with no temporal constraints (or with constraints currently satisfied) verifies successfully; a token whose expiration is in the past is rejected as expired; a token whose not-before instant is in the future is rejected as premature. Error outcomes carry only a neutral category (no wall-clock timestamps).",
  "cases": [
    {
      "input": {
        "op": "lifecycle",
        "sub": "Joe"
      },
      "expected_output": "valid=true\nsub=Joe"
    },
    {
      "input": {
        "op": "lifecycle",
        "sub": "Joe",
        "exp_offset_sec": -1000
      },
      "expected_output": "error=expired"
    },
    {
      "input": {
        "op": "lifecycle",
        "sub": "Joe",
        "nbf_offset_sec": 10000
      },
      "expected_output": "error=premature"
    }
  ]
}
